import groovy.json.JsonSlurper
import groovy.json.JsonOutput
import org.apache.commons.io.IOUtils

flowFile = session.get()
if (!flowFile) return

def text = ''
// Read entire FlowFile content to string
def callback = { inputStream -> text = IOUtils.toString(inputStream, 'UTF-8') } as org.apache.nifi.processor.io.InputStreamCallback
session.read(flowFile, callback)

def slurper = new JsonSlurper()
def json
try {
    json = slurper.parseText(text)
} catch (Exception e) {
    flowFile = session.putAttribute(flowFile, 'http.status.code', '400')
    def error = [error: 'Invalid JSON payload']
    flowFile = session.write(flowFile, { out -> out.write(JsonOutput.toJson(error).bytes) } as org.apache.nifi.processor.io.OutputStreamCallback)
    session.transfer(flowFile, REL_FAILURE)
    return
}

// Validation
if (!json.userId) {
    flowFile = session.putAttribute(flowFile, 'http.status.code', '400')
    def error = [error: 'Missing userId']
    flowFile = session.write(flowFile, { out -> out.write(JsonOutput.toJson(error).bytes) } as org.apache.nifi.processor.io.OutputStreamCallback)
    session.transfer(flowFile, REL_FAILURE)
    return
}
if (!json.order?.items || json.order.items.isEmpty()) {
    flowFile = session.putAttribute(flowFile, 'http.status.code', '400')
    def error = [error: 'order.items must be a non-empty array']
    flowFile = session.write(flowFile, { out -> out.write(JsonOutput.toJson(error).bytes) } as org.apache.nifi.processor.io.OutputStreamCallback)
    session.transfer(flowFile, REL_FAILURE)
    return
}
if (!json.order?.shipping?.address) {
    flowFile = session.putAttribute(flowFile, 'http.status.code', '400')
    def error = [error: 'Missing shipping.address']
    flowFile = session.write(flowFile, { out -> out.write(JsonOutput.toJson(error).bytes) } as org.apache.nifi.processor.io.OutputStreamCallback)
    session.transfer(flowFile, REL_FAILURE)
    return
}

// Business Logic
boolean discountApplied = false
BigDecimal total = 0.0
json.order.items.each { item -> total += item.quantity * item.price }
if (json.coupon == 'SAVE10') {
    total = total * 0.9
    discountApplied = true
}
BigDecimal shippingFee = 0.0
if (json.order.shipping.method == 'express') {
    shippingFee = 5.0
}

total += shippingFee

// Build response

def response = [
    orderId: UUID.randomUUID().toString(),
    userId: json.userId,
    finalAmount: total,
    discountApplied: discountApplied,
    shippingFee: shippingFee,
    status: 'confirmed'
]

flowFile = session.putAttribute(flowFile, 'http.status.code', '200')
session.write(flowFile, { out -> out.write(JsonOutput.toJson(response).bytes) } as org.apache.nifi.processor.io.OutputStreamCallback)
session.transfer(flowFile, REL_SUCCESS)

