import java.util.UUID
import org.apache.nifi.serialization.record.MapRecord
import org.apache.nifi.serialization.SimpleRecordSchema
import org.apache.nifi.serialization.record.RecordFieldType
import org.apache.nifi.serialization.record.RecordField

def rr = record
// Safely extract fields using Record API

def userId = rr.getValue('userId')?.toString() ?: ''

// Get the order record properly
def orderRecord = rr.getValue('order')
def items = []
def shippingMethod = 'standard'

if (orderRecord != null) {
    // Extract items array
    def itemsArray = orderRecord.getValue('items')
    if (itemsArray != null && itemsArray instanceof Object[]) {
        items = itemsArray as List
    }

    // Extract shipping method
    def shippingRecord = orderRecord.getValue('shipping')
    if (shippingRecord != null) {
        def method = shippingRecord.getValue('method')
        if (method != null) {
            shippingMethod = method.toString().toLowerCase()
        }
    }
}

def coupon = rr.getValue('coupon')?.toString()

def discountApplied = false
def shippingFee = (shippingMethod == 'express' ? 5.0 : 0.0)

// Calculate total from items
def total = 0.0
if (items) {
    total = items.collect { item ->
        def qty = item.getValue('quantity')?.doubleValue() ?: 0.0
        def price = item.getValue('price')?.doubleValue() ?: 0.0
        qty * price
    }.sum() as double
}

// Apply coupon discount
def validCoupon = (coupon == 'SAVE10')
if (validCoupon) {
    total *= 0.9
    discountApplied = true
}

total += shippingFee

// Create output schema
def outputFields = [
    new RecordField('orderId', RecordFieldType.STRING.getDataType()),
    new RecordField('userId', RecordFieldType.STRING.getDataType()),
    new RecordField('finalAmount', RecordFieldType.DOUBLE.getDataType()),
    new RecordField('discountApplied', RecordFieldType.BOOLEAN.getDataType()),
    new RecordField('shippingFee', RecordFieldType.DOUBLE.getDataType()),
    new RecordField('status', RecordFieldType.STRING.getDataType())
]
def outputSchema = new SimpleRecordSchema(outputFields)

// Build response record
def responseData = [
    'orderId': UUID.randomUUID().toString(),
    'userId': userId,
    'finalAmount': total,
    'discountApplied': discountApplied,
    'shippingFee': shippingFee,
    'status': 'confirmed'
]

return new MapRecord(outputSchema, responseData)

import groovy.json.JsonSlurper
import groovy.json.JsonOutput
import java.util.UUID
import org.apache.nifi.processor.io.OutputStreamCallback

// Get the flowFile
def flowFile = session.get()
if (!flowFile) return

try {
    // Get attributes and parse JSON
    def attrs = flowFile.getAttributes()
    def items = new JsonSlurper().parseText(attrs['items'])

    // Calculate totals
    def total = 0
    items.each { 
        total += it.quantity * it.price 
    }

    def discount = total * attrs['discountPercent'].toDouble()
    def finalAmt = total - discount + attrs['shippingFee'].toDouble()

    // Create response object
    def response = [
        orderId: UUID.randomUUID().toString(), 
        userId: attrs['userId'], 
        finalAmount: finalAmt, 
        discountApplied: attrs['discountApplied'].toBoolean(), 
        shippingFee: attrs['shippingFee'].toDouble(), 
        status: 'confirmed'
    ]

    // Write response to flowFile
    flowFile = session.write(flowFile, { outputStream ->
        outputStream.write(JsonOutput.toJson(response).getBytes('UTF-8'))
    } as OutputStreamCallback)

    // Set MIME type attribute
    flowFile = session.putAttribute(flowFile, 'mime.type', 'application/json')

    // Transfer to success
    session.transfer(flowFile, REL_SUCCESS)
} catch (Exception e) {
    log.error("Failed to process FlowFile: {}", e)
    session.transfer(flowFile, REL_FAILURE)
}

const FlowFile = Java.type('org.apache.nifi.flowfile.FlowFile');
const StandardCharsets = Java.type('java.nio.charset.StandardCharsets');
const IOUtils = Java.type('org.apache.commons.io.IOUtils');
const StreamCallback = Java.type('org.apache.nifi.processor.io.StreamCallback');
const UUID = Java.type('java.util.UUID');

let flowFile = session.get();
if (flowFile === null) {
    return;
}

try {
    const content = session.read(flowFile, inputStream => IOUtils.toString(inputStream, StandardCharsets.UTF_8));
    const data = JSON.parse(content);

    // Validation
    if (!data.userId || !data.order || !data.order.items || data.order.items.length === 0 || !data.order.shipping || !data.order.shipping.address) {
        session.transfer(flowFile, REL_FAILURE);
        return;
    }

    let finalAmount = 0;
    let discountApplied = false;
    let shippingFee = 0;

    data.order.items.forEach(item => {
        finalAmount += item.quantity * item.price;
    });

    if (data.coupon === 'SAVE10') {
        finalAmount *= 0.9;
        discountApplied = true;
    }

    if (data.order.shipping.method === 'express') {
        shippingFee = 5.0;
        finalAmount += shippingFee;
    }

    const orderId = UUID.randomUUID().toString();

    const response = {
        orderId: orderId,
        userId: data.userId,
        finalAmount: finalAmount,
        discountApplied: discountApplied,
        shippingFee: shippingFee,
        status: "confirmed"
    };

    flowFile = session.write(flowFile, new StreamCallback(function(inputStream, outputStream) {
        outputStream.write(JSON.stringify(response, null, 2).getBytes(StandardCharsets.UTF_8));
    }));

    session.transfer(flowFile, REL_SUCCESS);

} catch (e) {
    log.error('Error processing order', e);
    session.transfer(flowFile, REL_FAILURE);
}

import groovy.json.JsonSlurper; import groovy.json.JsonOutput; import java.util.UUID;
