def discountApplied = ('SAVE10'.equals(json.coupon)); if (discountApplied) total *= 0.9;
// Shipping fee
def shippingFee = ('express'.equals(json.order.shipping.method)) ? 5.0 : 0.0;
def finalAmount = total + shippingFee;
// Build response JSON
